[
  {
    "name": "Linnaeus' System of Classification",
    "formula": "Kingdom > Division > Class > Order > Family > Genus > Species",
    "notes": "A hierarchical system to classify living organisms"
  },
  {
    "name": "Whittaker's System of Classification",
    "formula": "Domain > Kingdom > Phylum > Class > Order > Family > Genus > Species",
    "notes": "An expanded version of Linnaeus' system, including the domain level"
  },
  {
    "name": "Robert Hooke's Law of Biological Classification",
    "formula": "All living organisms can be classified into two groups: Monerans and Protists",
