  },
  {
    "name": "Schwann's Law of Biological Classification",
    "formula": "All living organisms can be classified into two groups: Monerans and Metazoa",
    "notes": "A further classification system based on cell structure and presence of true tissues"
  },
  {
    "name": "Batsch's Law of Biological Classification",
    "formula": "All living organisms can be classified into three groups: Plantae, Animalia, and Fungi",
    "notes": "An early classification system based on presence of chlorophyll"
  },
  {
    "name": "Duchesne's Law of Biological Classification",
    "formula": "All living organisms can be classified into two groups: Sporozoans and Multicellular organisms",
